// nodes/llmNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const LLMNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [model, setModel] = useState(data?.model ?? 'gpt-4o');
  const [temperature, setTemperature] = useState(data?.temperature ?? '0.7');

  return (
    <BaseNode
      id={id}
      title="LLM"
      icon="🧠"
      accentColor="#a78bfa"
      inputs={[
        { id: 'system', label: 'system' },
        { id: 'prompt', label: 'prompt' },
      ]}
      outputs={[{ id: 'response', label: 'response' }]}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Model</label>
        <select
          style={fieldStyle.select}
          value={model}
          onChange={(e) => {
            setModel(e.target.value);
            updateNodeField(id, 'model', e.target.value);
          }}
        >
          <option value="gpt-4o">GPT-4o</option>
          <option value="gpt-4-turbo">GPT-4 Turbo</option>
          <option value="gpt-3.5-turbo">GPT-3.5 Turbo</option>
          <option value="claude-3-5-sonnet">Claude 3.5 Sonnet</option>
          <option value="gemini-1.5-pro">Gemini 1.5 Pro</option>
        </select>
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Temperature</label>
        <input
          style={fieldStyle.input}
          type="number"
          min="0"
          max="2"
          step="0.1"
          value={temperature}
          onChange={(e) => {
            setTemperature(e.target.value);
            updateNodeField(id, 'temperature', e.target.value);
          }}
        />
      </div>
    </BaseNode>
  );
};
